insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Gnocchi with Pesto & Green Beans', 'A family-friendly tray-bake supper that''s low on cost and cooked on a single tray.', null, '[{"id":"ebbfbb82-0c0b-400c-a0b0-e9086a011d6e","name":"Sweet peppers","quantity":3,"unit":"pieces"},{"id":"7c5c6581-86f9-4ac9-8968-72833b6ea7d0","name":"Olive oil","quantity":1.5,"unit":"tbsp"},{"id":"68860444-4528-45dc-a10a-33a289553aec","name":"Gnocchi","quantity":500,"unit":"g"},{"id":"15c3b4f4-c6a8-4e40-a38b-95a6936019f8","name":"Green beans","quantity":300,"unit":"g"},{"id":"b4457cc2-45eb-4794-83f3-9b113c90c4a5","name":"Green pesto","quantity":145,"unit":"g"}]'::jsonb,
       array['Preheat the oven to 200°C (gas mark 6). Deseed the sweet peppers and cut into strips. Toss with 1 tbsp of the oil in a roasting tin and roast for 15 minutes.', 'Put the gnocchi in a heatproof bowl and cover with just-boiled water from the kettle. Set aside for 3 minutes, then drain.', 'Trim the ends of the green beans. Add the gnocchi and beans to the roasting tin, sprinkle over the remaining ½ tbsp oil, season, and roast for a further 10 minutes.', 'As soon as the tin comes out of the oven, stir the pesto through the gnocchi, peppers and beans. Divide between plates with wild rocket and shavings of Parmigiano Reggiano, if liked.']::text[], array['dinner']::text[], 4, 'Optional to serve: wild rocket leaves and Parmigiano Reggiano shavings. Cook''s tip — swap the green pesto for red chilli pesto and add some cherry tomatoes for a different flavour.', '', array['vegetarian', 'one-tray', 'quick', 'family-favourite']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Gnocchi with Pesto & Green Beans'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Salmon & Avocado Noodles', 'A quick midweek bowl of egg noodles, salmon and avocado with a salty-sweet soy-ginger dressing.', null, '[{"id":"22dab6fb-6015-4e7d-a860-20d588081251","name":"Edamame beans (frozen)","quantity":160,"unit":"g"},{"id":"28eb8209-81e4-4e03-a892-5afba4473358","name":"Salmon fillets","quantity":2,"unit":"pieces"},{"id":"095ea8f9-feb6-46f1-9ed3-4913ac806753","name":"Egg noodles","quantity":275,"unit":"g"},{"id":"37732aca-70af-4d7a-86f3-74c9666d77d7","name":"Avocado","quantity":1,"unit":"pieces"},{"id":"6804301c-cf1b-43bb-a212-b0f8db0aed91","name":"Salad onions","quantity":2,"unit":"pieces"},{"id":"c56b4af0-5a01-489c-8f32-1a8d65615f95","name":"Soy sauce","quantity":2,"unit":"tbsp"},{"id":"49f4ccc9-f370-4225-9873-9974ce37e520","name":"Mirin","quantity":1,"unit":"tbsp"},{"id":"2a509db7-d886-4a2d-8348-a86958d98a5c","name":"Maple syrup","quantity":2,"unit":"tsp"},{"id":"8f406935-5a5a-4298-a0c9-2adc3e58a5e6","name":"Toasted sesame oil","quantity":1,"unit":"tsp"},{"id":"f5872bef-c5ce-4235-92f2-d5ff6cc660bb","name":"Ginger","quantity":0.5,"unit":"tsp"},{"id":"4e8a4062-3fc1-44f2-9874-165c3088b6ba","name":"Shichimi togarashi","quantity":1,"unit":"tsp"}]'::jsonb,
       array['Preheat the grill to high. Cook the edamame beans according to pack instructions, drain and set aside.', 'Make the soy-ginger dressing by mixing the soy sauce, mirin, maple syrup, sesame oil and grated ginger in a small bowl.', 'Arrange the salmon, skin-side down, on a foil-lined baking tray. Spoon over 2 tsp of the dressing. Grill for 6–8 minutes, until the fish is opaque and flakes easily.', 'Meanwhile, cook the egg noodles according to pack instructions and divide between shallow bowls.', 'Slice the avocado and finely slice the salad onions. Top each bowl with a salmon fillet, the edamame beans, avocado and salad onions. Spoon over the remaining dressing and sprinkle with shichimi togarashi, if liked.']::text[], array['dinner']::text[], 2, 'Cook''s tip — Mirin is a Japanese rice wine, similar to sake but lower in alcohol and sweeter. If you don''t have any, substitute a splash of sherry or rice vinegar. The shichimi togarashi is optional.', '', array['quick', 'fish', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Salmon & Avocado Noodles'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Smoky Barbecue Beans, Sweet Potato Fries & Guac', 'Smoky tomatoey beans with crispy sweet potato wedges and fresh guacamole. Vegan and low carbon impact.', null, '[{"id":"12083c39-4958-4796-a942-2e1da98599ce","name":"Sweet potato","quantity":1,"unit":"pieces"},{"id":"b164c1aa-9c6f-43ea-a89a-94bc210af9be","name":"Garlic cloves","quantity":2,"unit":"pieces"},{"id":"a89afc64-0fff-4832-8847-39302b975de7","name":"Onion","quantity":1,"unit":"pieces"},{"id":"c8e53a11-4d7a-4fbe-bfca-edab8725f1b8","name":"Courgette","quantity":1,"unit":"pieces"},{"id":"3e6e5253-9003-4192-9d75-951483c26c83","name":"Haricot beans","quantity":240,"unit":"g"},{"id":"25b7b81f-44db-475d-9d9b-582866b48ac8","name":"Smoked paprika","quantity":2,"unit":"tsp"},{"id":"1e9982c7-54bf-401d-a0f0-36f5334b206d","name":"Chilli flakes","quantity":1,"unit":"tsp"},{"id":"29b60463-fdde-4f53-9918-8c9b89d54481","name":"Passata","quantity":200,"unit":"g"},{"id":"4fcc5e30-ad97-4992-b350-bf9fe450a1d0","name":"Balsamic vinegar","quantity":1,"unit":"tbsp"},{"id":"7388ea46-3660-4bfb-bbdc-96747b4cca48","name":"Maple syrup","quantity":2,"unit":"tsp"},{"id":"d1e4ada4-b28f-40af-9f5f-75957df6d105","name":"Fresh coriander","quantity":1,"unit":"bunch"},{"id":"e3bb7ff4-f04c-495b-b029-6bb19fde1661","name":"Lime","quantity":1,"unit":"pieces"},{"id":"3d0acfa3-2260-4b65-b8aa-feaaba39e9d7","name":"Avocado","quantity":1,"unit":"pieces"},{"id":"c6e88d10-77c3-4790-a9a4-ea89282cd32a","name":"Olive oil","quantity":1,"unit":"tbsp"}]'::jsonb,
       array['Preheat the oven to 220°C (fan 200°C / gas mark 7) and line a baking tray with parchment. Cut the sweet potato into 2 cm thick wedges, toss with ½ tbsp oil and a pinch of salt and pepper on the tray, and roast for 20–25 minutes until soft and golden.', 'Meanwhile, finely chop or crush the garlic. Finely slice three-quarters of the onion and finely dice the rest. Thinly slice the courgette into half-moons. Drain and rinse the haricot beans.', 'Heat a large saucepan with the remaining ½ tbsp oil over medium heat. Add the garlic and sliced onion and cook for 3 minutes. Season, then add the courgette, paprika and chilli flakes (to taste) and cook for a further 3 minutes.', 'Add the beans, passata, balsamic vinegar and maple syrup. Simmer for 8–10 minutes, until the sauce thickens.', 'Roughly chop the coriander and halve the lime. Mash the avocado in a small bowl, then mix in the diced onion, coriander and a squeeze of lime juice. Season to taste.', 'Serve the barbecue beans with the guacamole and sweet potato wedges. Garnish with the remaining lime, cut into wedges.']::text[], array['dinner']::text[], 2, 'Halve the ingredients to serve 1. The dish is vegan as written.', '', array['vegan', 'midweek', 'low-carbon']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Smoky Barbecue Beans, Sweet Potato Fries & Guac'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Chilli Crab & Toasted Corn Linguine', 'Speedy pasta with charred sweetcorn, mild red chilli, parsley and crab — ready in 20 minutes.', null, '[{"id":"b3ad35e2-3882-4bf7-9ba0-df4bfd4e62de","name":"Sweetcorn (frozen)","quantity":160,"unit":"g"},{"id":"5bac6e46-46ec-4d72-870b-c0611774b30c","name":"Dried linguine","quantity":180,"unit":"g"},{"id":"ec94e03d-d5c8-4175-9ed6-deb9ed9ecb77","name":"Olive oil","quantity":2.5,"unit":"tbsp"},{"id":"16e8775a-7588-4352-a0ec-5867f83bdd41","name":"Garlic cloves","quantity":1,"unit":"pieces"},{"id":"36f9631e-9467-4641-ae2c-1000b01f23eb","name":"Mild red chilli","quantity":1,"unit":"pieces"},{"id":"0927c2a6-8779-42b8-9beb-3c8b265de376","name":"Flat leaf parsley","quantity":2,"unit":"tbsp"},{"id":"ec1855ee-1ce6-4a39-855c-ddd0599d0af3","name":"Crab meat (50/50 white & brown)","quantity":100,"unit":"g"},{"id":"67b63481-211e-460d-aead-11829f5acae3","name":"Unwaxed lemon","quantity":0.5,"unit":"pieces"}]'::jsonb,
       array['Heat a medium-large nonstick frying pan over a high heat. Add the corn and dry-fry, stirring regularly, for 5 minutes until lightly charred in places and piping hot. Tip into a bowl and set aside. Meanwhile, cook the pasta in a large saucepan of salted boiling water for 1 minute less than the pack instructions.', 'Five minutes before the pasta is ready, return the frying pan to a medium heat with the oil, finely chopped garlic, deseeded and finely chopped chilli, and finely chopped parsley. Cook gently for 2 minutes, then stir in the crab and warm everything through.', 'Scoop out a mugful of the pasta cooking water, then drain the pasta and add to the frying pan with a glug of the cooking water. Toss over the heat with the charred corn and the lemon zest and juice until piping hot. Divide between plates and serve straight away.']::text[], array['dinner']::text[], 2, 'Cook''s tip — 50/50 crab is a mix of white and brown crabmeat. If you prefer a milder crab flavour, use all-white meat.', '', array['quick', 'fish', 'pasta']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Chilli Crab & Toasted Corn Linguine'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Salmon & Watercress Spaghetti', 'A tub of watercress tzatziki creates an almost instant sauce for this speedy pasta dish.', null, '[{"id":"7309b547-b56b-4d91-b7d8-581414de95ce","name":"Dried spaghetti","quantity":180,"unit":"g"},{"id":"d57d3ef2-09da-4dd8-bf70-596f3348cbae","name":"Purple sprouting broccoli","quantity":230,"unit":"g"},{"id":"37608ebc-9538-40c2-a92a-c23f7b1a5dc2","name":"Scottish poached salmon fillets","quantity":2,"unit":"pieces"},{"id":"728425b5-cbea-40de-82cb-31e528ce4f79","name":"Watercress tzatziki","quantity":170,"unit":"g"},{"id":"9a7f5837-b3a2-4341-8e54-ac6696a797bb","name":"Unwaxed lemon","quantity":0.5,"unit":"pieces"},{"id":"00235bcd-eda2-48d6-87f1-da49623efe11","name":"Parmigiano Reggiano","quantity":10,"unit":"g"}]'::jsonb,
       array['Bring a large saucepan of salted water to the boil. Add the spaghetti and simmer for a minute less than pack instructions, adding the broccoli (cut into 3–4 cm pieces) to the pan for the final 3 minutes of cooking time. Before draining, scoop out a mugful of the cooking water. Meanwhile, flake the salmon and remove the skin.', 'Tip the drained pasta back into the pan (off the heat). Add the flaked salmon, tzatziki, lemon zest and a squeeze of juice, the cheese and 3 tbsp of the pasta cooking water. Toss together with tongs to combine and serve with extra grated cheese.']::text[], array['dinner']::text[], 2, 'Boost fibre by using wholewheat spaghetti and add some frozen peas with the broccoli, if liked.', '', array['quick', 'fish', 'pasta', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Salmon & Watercress Spaghetti'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Cheddar & Leek Orzotto', 'A pleasingly simple twist on risotto that''s quicker to make but just as gratifying as the original.', null, '[{"id":"cb62cb56-cd78-476b-80dc-a920b6d8ebd8","name":"Leek (large, ~250g)","quantity":1,"unit":"pieces"},{"id":"c6cb8135-197f-491b-8a74-5f8c9a3034a7","name":"Unsalted butter","quantity":20,"unit":"g"},{"id":"240e1bea-db88-4519-bce6-f17664741bf3","name":"Olive oil","quantity":1,"unit":"tbsp"},{"id":"52ba5ac9-c535-4d7e-91ab-56cad756b14a","name":"Garlic cloves","quantity":1,"unit":"pieces"},{"id":"f8229904-bc3b-41f5-8a27-667ef03ccaf6","name":"Orzo pasta","quantity":150,"unit":"g"},{"id":"b83e59a9-aaa0-42b5-9197-890414fd8213","name":"Chicken or vegetable stock","quantity":500,"unit":"ml"},{"id":"32098c82-f5ae-4a98-9e17-2f8455ab1a18","name":"Petits pois (frozen)","quantity":100,"unit":"g"},{"id":"d7a87dec-f7fd-404f-83b2-a5e9894a686f","name":"Mature cheddar","quantity":80,"unit":"g"}]'::jsonb,
       array['Halve the leek lengthways, then halve again into quarters and finely slice. Heat the butter and olive oil in a medium-large saucepan over a medium-high heat. Add the leek, finely chopped garlic and a pinch of salt and cook, stirring regularly, for 5 minutes until soft but without any colour.', 'Add the orzo to the pan and stir through the leek. Cook, stirring, for 2 minutes. Add 400 ml of the stock, bring to the boil, then reduce to a gentle simmer. Cook for about 4 minutes, stirring regularly, then stir in the peas. Cook for another 4 minutes, adding more stock if it looks dry (it should be a loose consistency). The orzo is ready when tender but with just a little bite.', 'Take off the heat and stir in half of the cheddar, then let stand for 2 minutes. Sprinkle the remaining cheese over the top and serve with a grinding of black pepper.']::text[], array['dinner']::text[], 2, 'Cook''s tip — Use fresh stock if you can; its flavour really comes through in the orzotto.', '', array['vegetarian', 'quick', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Cheddar & Leek Orzotto'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Courgette, Chickpea & Feta Pasta', 'A great-value, great-tasting weeknight pasta — the chickpeas pack in fibre and protein.', null, '[{"id":"427a4474-2ab3-45aa-aa5d-20adff4b1a09","name":"Olive oil","quantity":3,"unit":"tbsp"},{"id":"6a30988d-86af-4020-9e17-a507249a8151","name":"Courgettes","quantity":500,"unit":"g"},{"id":"733808a5-057a-4f1f-8aed-1d541f29e13d","name":"Garlic cloves","quantity":3,"unit":"pieces"},{"id":"aae66a02-c63e-4f50-83e0-ca30fecc4e2b","name":"Chifferi rigati (or other short) pasta","quantity":300,"unit":"g"},{"id":"4cd361d2-e1d6-4abc-bcb9-c37a6b4cd919","name":"Chickpeas (tinned)","quantity":1,"unit":"tin"},{"id":"3c8789fd-5674-4c9e-b4ce-cb61e8b0ef69","name":"Lemon","quantity":1,"unit":"pieces"},{"id":"1001b841-ef65-4213-9d77-3a9260fced43","name":"Chilli flakes","quantity":0.5,"unit":"tsp"},{"id":"a9744670-f1c2-40c2-9cf6-b22baccebe1b","name":"Feta","quantity":120,"unit":"g"},{"id":"058f340c-6ff6-4ac2-bc38-f6317d3318fe","name":"Basil","quantity":1,"unit":"bunch"}]'::jsonb,
       array['Heat the oil in a large frying pan over a medium-high heat. Add the thinly sliced courgettes and sliced garlic with a large pinch of salt. Fry for 10–12 minutes until tender and golden.', 'Once the courgettes are turning golden, bring a large pan of salted water to the boil. Add the pasta and cook according to pack instructions. Scoop out a mugful of cooking water, then drain.', 'Meanwhile, add the drained and rinsed chickpeas to the courgette pan, turn the heat up to high and fry for another 5 minutes. Stir in the drained pasta, 3 tbsp pasta cooking water, the lemon zest and the juice of ½ the lemon, and the chilli flakes. Toss together. Take off the heat and stir through the crumbled feta and shredded basil (if using). Season and serve immediately with freshly ground black pepper.']::text[], array['dinner']::text[], 4, 'Cook''s tip — chilli flakes vary in heat; add a little, taste, then add more. Sub in paprika to skip the heat. Basil is optional.', '', array['vegetarian', 'pasta', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Courgette, Chickpea & Feta Pasta'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Conchiglie with Mushrooms & Spinach', 'A veg-packed pasta bake with porcini, chestnut mushrooms, wilted spinach and a creamy parmesan sauce.', null, '[{"id":"b9275872-4cc9-469f-b25e-c3c8cc3033cf","name":"Dried porcini mushrooms","quantity":15,"unit":"g"},{"id":"65b8276c-31e7-4baa-a1c3-9dce385bdaa3","name":"Spinach (ready-washed)","quantity":235,"unit":"g"},{"id":"7d318791-cf39-453b-9735-e5d438528fd0","name":"Conchiglie rigate pasta","quantity":300,"unit":"g"},{"id":"5420dd55-797b-48a9-975b-cd2bc1566f2d","name":"Olive oil","quantity":1,"unit":"tbsp"},{"id":"3d1aa28c-0784-45b5-b7bb-3ea7df590a6d","name":"Echalion shallots","quantity":2,"unit":"pieces"},{"id":"2c9f39bd-c824-464d-9016-ad34ca01206d","name":"Chestnut mushrooms","quantity":250,"unit":"g"},{"id":"3014a6e4-2bf8-475c-833c-3d8dc14e4545","name":"Garlic cloves","quantity":2,"unit":"pieces"},{"id":"f83a9f5e-841e-454c-9418-f7c3432d6641","name":"Double cream","quantity":6,"unit":"tbsp"},{"id":"06d3c98f-c5b8-4cea-80ad-5e2343a2b41b","name":"Parmigiano Reggiano","quantity":60,"unit":"g"}]'::jsonb,
       array['Preheat the grill to high and put an oven shelf in the top third of the oven. Boil a kettle. Put the dried porcini in a heatproof bowl and cover with 300 ml just-boiled water; set aside. Put the spinach in a large mixing bowl and pour over enough just-boiled water to wilt. Drain through a sieve, rinse under the cold tap, squeeze out the excess liquid and pat dry with kitchen paper.', 'Bring a large saucepan of water to the boil and cook the pasta for 1 minute less than pack instructions. In a separate large, shallow casserole, heat the oil over medium-high heat. Add the finely diced shallots, sliced chestnut mushrooms, crushed garlic and a pinch of salt. Cover with a lid and sweat for 5 minutes, stirring occasionally. Uncover and fry for another 5 minutes.', 'Lift the porcini out of the soaking liquid, squeezing any excess back into the bowl (reserve the liquid). Finely chop the porcini and roughly chop the spinach, then stir both into the casserole. Add 200 ml of the mushroom soaking liquid (leaving any sediment behind) and the cream. Drain the pasta and tip into the casserole with ⅔ of the parmesan. Season and stir together over the heat for 1 minute.', 'Scatter over the remaining cheese and grill for 2–3 minutes until golden. Stand for 2 minutes before serving in bowls.']::text[], array['dinner']::text[], 4, 'Cook''s tip — Blanching and drying the spinach first stops the sauce becoming watery.', '', array['vegetarian', 'pasta']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Conchiglie with Mushrooms & Spinach'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Smoky Grains with Courgette & Butter Beans', 'An easy vegan supper of charred courgette ribbons, crispy paprika butter beans and Spanish-style grains, lifted with mint and lemon.', null, '[{"id":"ade9524d-1e81-4144-a5c4-2b664d7e17c7","name":"Courgettes (medium)","quantity":2,"unit":"pieces"},{"id":"4c99bb52-c578-477b-8f33-fc1275584c3f","name":"Olive oil","quantity":2,"unit":"tbsp"},{"id":"946ecbc5-2e18-4ba5-bb4b-13b95d3d6c6e","name":"Garlic cloves","quantity":1,"unit":"pieces"},{"id":"cac0ea04-7440-4a63-85a4-7842d6975d40","name":"Butter beans (tinned)","quantity":1,"unit":"tin"},{"id":"69615c90-7c45-4f6e-bd02-dd679cf33f74","name":"Hot smoked paprika","quantity":0.5,"unit":"tsp"},{"id":"e7ab6bfd-da7c-443e-8607-bdaf8b3505a6","name":"Spanish-style grains & rice pouch","quantity":1,"unit":"pack"},{"id":"0e42bbf4-7a80-4631-978a-e7caa65557c6","name":"Lemon","quantity":0.5,"unit":"pieces"},{"id":"bad6c000-5d7f-435a-8d32-ab89e00cc8ec","name":"Mint","quantity":1,"unit":"bunch"}]'::jsonb,
       array['Heat a griddle or large frying pan over a high heat. Slice the courgettes lengthways into thin strips. Put 1 tbsp of the oil in a mixing bowl and toss the courgette strips to coat. Fry in batches for 2 minutes on each side until soft and golden, then season lightly. Keep the mixing bowl with any leftover oil.', 'Add the remaining 1 tbsp oil and the finely grated garlic to the mixing bowl, then add the drained, rinsed and patted-dry butter beans and coat them in the oil and garlic. Sprinkle with the paprika, then fry the beans in the pan for 5–6 minutes until golden. Reserve the bowl with any leftover oil and garlic.', 'Heat the grains according to pack instructions. Squeeze the juice of ¼ of the lemon into the mixing bowl, then toss in the warm grains. Stir through the shredded mint leaves (about 20) and the crispy butter beans. Divide between plates, arrange the courgette strips on top, and serve with the remaining lemon, cut into wedges.']::text[], array['dinner']::text[], 2, 'Cook''s tip — for extra protein and crunch, add toasted nuts or seeds. Pistachios or pumpkin seeds work brilliantly.', '', array['vegan', 'quick', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Smoky Grains with Courgette & Butter Beans'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Salmon with Citrus Slaw', 'Grilled salmon with a bright tangerine-and-soy slaw of beetroot, carrot, cabbage and red onion, finished with toasted pecans.', null, '[{"id":"193f208e-35e8-45bb-a873-cf7e71afdd3b","name":"Pecans","quantity":30,"unit":"g"},{"id":"86146c18-d19d-4ec3-8b5c-9668fff04304","name":"Tangerines","quantity":2,"unit":"pieces"},{"id":"5252dfa7-b627-462d-aa9f-0b784d62bf40","name":"Ginger","quantity":0.5,"unit":"tsp"},{"id":"0f7b3c7a-6c06-4c8b-9d7e-d8c20367b90c","name":"Garlic cloves","quantity":1,"unit":"pieces"},{"id":"edb7fc5c-7a0c-4d9d-ad54-06014f3c12a0","name":"Soy sauce (reduced salt)","quantity":1.5,"unit":"tbsp"},{"id":"24d12e07-3c8a-4ee4-b210-236ccabbe96a","name":"Toasted sesame oil","quantity":1,"unit":"tsp"},{"id":"cd255ce3-6886-4bc7-a8b2-1a794d61ab53","name":"Salmon tail fillets","quantity":2,"unit":"pieces"},{"id":"a1795216-8156-46c0-99d1-2cbc0ac38996","name":"Raw beetroot (~100g)","quantity":1,"unit":"pieces"},{"id":"4260e711-5af9-44e8-943d-dbe44a696bcd","name":"Carrot (small)","quantity":1,"unit":"pieces"},{"id":"35ee3e49-898b-4bdc-90a3-542e269600a0","name":"Pointed spring cabbage","quantity":0.25,"unit":"pieces"},{"id":"c1690116-e9fb-4f35-b693-c24f35739a51","name":"Red onion (small)","quantity":0.5,"unit":"pieces"}]'::jsonb,
       array['Preheat the oven to 180°C (gas mark 4). Roast the pecans for 5 minutes, then set aside. Meanwhile, mix the juice of 1 tangerine with the finely grated ginger, finely grated garlic, soy sauce and sesame oil. Use 2 tbsp of the dressing to marinate the salmon and set the rest aside.', 'For the slaw, finely slice the trimmed and peeled beetroot into rounds, then cut into thin matchsticks. Put in a bowl with the grated or julienned carrot, shredded cabbage and finely sliced red onion. Peel the remaining tangerine, separate into segments, and cut each into thirds. Set everything aside.', 'Turn the grill to high. Put the salmon (skin removed) on a foil-lined baking tray and grill for 5–6 minutes, until opaque and fully cooked. Toss the shredded vegetables with the remaining dressing, then toss through the pecans and tangerine pieces. Divide between plates and top with the salmon.']::text[], array['dinner']::text[], 2, 'Cook''s tip — a julienne peeler is really useful for making slaws. If cutting by hand, sharpen your knife first for neat, thin slices.', '', array['fish', 'quick', 'midweek', 'healthy']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Salmon with Citrus Slaw'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Tomato & Basil Pasta Salad', 'A Sicilian-inspired pasta salad where fresh tomatoes form the base of the pesto. Use a vegetarian hard cheese if you prefer.', null, '[{"id":"b9f50f8f-9e1c-4507-85cb-b408fa174bc7","name":"Basil","quantity":25,"unit":"g"},{"id":"53cbc773-16b6-4091-a711-0bdb6fdb3956","name":"Garlic cloves","quantity":1,"unit":"pieces"},{"id":"8747dd41-eac3-409f-bd0f-83710a8139d6","name":"Toasted flaked almonds","quantity":50,"unit":"g"},{"id":"57946802-3b6e-4f64-8202-e08e987ed495","name":"Salt","quantity":1,"unit":"tsp"},{"id":"8f48fd27-7650-45c7-ae3d-00d38e827e3f","name":"Vine tomatoes","quantity":300,"unit":"g"},{"id":"3193a562-1355-46ad-a20d-cf6c4777983c","name":"Olive oil (extra virgin)","quantity":4,"unit":"tbsp"},{"id":"868da673-22da-4355-875a-3413a44a8df4","name":"Lemon juice","quantity":1,"unit":"tbsp"},{"id":"c25496f0-ab30-40e1-a800-7ba936f3c4aa","name":"Fusilli (or other short pasta)","quantity":350,"unit":"g"},{"id":"287bebf1-4d87-4109-8e03-eb2dbe45c92e","name":"Wild rocket","quantity":45,"unit":"g"},{"id":"50fb4e47-f2d3-44c4-82ba-4035d25523b2","name":"Pecorino","quantity":50,"unit":"g"}]'::jsonb,
       array['Put the basil, roughly chopped garlic and almonds in a food processor with the salt. Whizz to a sticky paste. Roughly chop the tomatoes, then add two-thirds to the processor with the oil and lemon juice. Pulse together to a loose pesto, then tip into a large mixing bowl.', 'Bring a large pan of salted water to the boil. Cook the pasta according to pack instructions, then drain. Toss the hot pasta and rocket through the pesto and allow to cool for 5 minutes.', 'Add the remaining chopped tomatoes to the bowl with the shaved or grated pecorino and some extra toasted flaked almonds. Serve.']::text[], array['lunch', 'dinner']::text[], 4, 'Leftovers — pecorino is a mild, slightly salty sheep''s-milk cheese. Use it as you would Parmigiano Reggiano.', '', array['vegetarian', 'pasta', 'summer']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Tomato & Basil Pasta Salad'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Thai-Style Salmon Curry', 'A warming one-pan curry ready in half an hour, using frozen Thai green herb portions for a quick aromatic base.', null, '[{"id":"9f446c5a-ba0b-4a64-aebc-a62fb6153ef2","name":"Sunflower oil","quantity":1,"unit":"tbsp"},{"id":"3f70f1b3-e48f-4b4d-8a58-5441473f037c","name":"Thai green herb portions (frozen)","quantity":100,"unit":"g"},{"id":"14b4ecc0-15ad-4c34-a35f-fdabf691ffb1","name":"Coconut milk (reduced fat)","quantity":1,"unit":"tin"},{"id":"42dbe30e-45e6-46bf-adf5-74fe7d5c5c12","name":"Fish sauce","quantity":1,"unit":"tbsp"},{"id":"7b8df21c-b2e3-42d7-95ca-f28ba4dd763e","name":"Maple syrup","quantity":1,"unit":"tsp"},{"id":"1ea02aea-20fa-477b-bfd8-336959d1b68b","name":"Salmon fillets","quantity":4,"unit":"pieces"},{"id":"c5f992c9-dfc7-42c5-b0d9-176ae8759d90","name":"Sugar snap peas","quantity":320,"unit":"g"},{"id":"93db7133-75cb-4227-bf6e-baccda69251c","name":"Lime","quantity":1,"unit":"pieces"},{"id":"4d095a06-c6ea-491c-85a2-fafe792a68da","name":"Coriander","quantity":1,"unit":"bunch"},{"id":"822021c8-b45c-468c-a2b4-3d1c97898eb4","name":"Rice (to serve)","quantity":300,"unit":"g"}]'::jsonb,
       array['Heat the oil in a large sauté pan or shallow casserole dish over a medium-high heat. Add the Thai green herb portions and cook, stirring, for 3–4 minutes. Add the coconut milk, fish sauce and maple syrup, and simmer for 5–6 minutes.', 'Turn the heat to medium-low. Add the salmon fillets (skin removed), skinned-side up, cover with a lid and simmer gently for 8–10 minutes. Turn the fillets over, add the sugar snaps, cover again, and simmer for a final 4 minutes, until the salmon is opaque and flakes easily.', 'Allow to stand for 1 minute, then squeeze over the juice of ½ the lime. Serve with the rest of the lime cut into wedges, coriander leaves and steamed rice.']::text[], array['dinner']::text[], 4, 'Leftovers — fish sauce stores well in the fridge. Use it to add umami to curries, stews and salad dressings, or as an anchovy substitute in pasta sauces. Caster sugar can replace the maple syrup.', '', array['fish', 'midweek', 'curry']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Thai-Style Salmon Curry'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Sweet Chilli Salmon Chopped Salad', 'A zingy no-cook salad with hot-smoked sweet chilli salmon, ready in under 20 minutes.', null, '[{"id":"7fb8ce7b-7bb2-49e2-97da-01e0291c7f31","name":"Romaine lettuce","quantity":1,"unit":"pieces"},{"id":"f2cc2c04-d868-4b41-9f8c-84786a4b25ed","name":"Avocado (small)","quantity":1,"unit":"pieces"},{"id":"faf3cc89-4d7c-4da2-afd1-8ce34e5bf92a","name":"Cucumber","quantity":200,"unit":"g"},{"id":"d574a761-02e8-4871-8ff2-21f9ad25910f","name":"Red onion","quantity":0.5,"unit":"pieces"},{"id":"4f7d0c64-563a-420d-a1a0-7fbce451ab87","name":"Cooked quinoa (red & white)","quantity":250,"unit":"g"},{"id":"e6678cc7-a147-46e6-866b-59172e9efbb6","name":"Coriander","quantity":1,"unit":"bunch"},{"id":"c1f9dfef-3827-4b03-a24a-6f779ca70495","name":"Hot smoked salmon (sweet chilli)","quantity":160,"unit":"g"},{"id":"afc203a3-be0d-4bc1-8d15-2a47a0a51ed7","name":"Soy sauce","quantity":2,"unit":"tsp"},{"id":"2e4a47c7-f021-4ab8-8bb7-4f857ac3f489","name":"Olive oil","quantity":2,"unit":"tsp"},{"id":"a9b363e6-4201-44b1-a11c-d106bb9535ba","name":"Balsamic vinegar","quantity":1,"unit":"tbsp"},{"id":"e756696d-e295-4d56-b09e-fc0decf5e915","name":"Clear honey","quantity":0.5,"unit":"tsp"},{"id":"a5324f40-88a1-40e9-b05c-b9d2482950d9","name":"Toasted sesame oil","quantity":1,"unit":"tsp"},{"id":"bea665f2-cd42-444c-bd23-26abf02cfb8b","name":"Garlic cloves","quantity":1,"unit":"pieces"}]'::jsonb,
       array['In a large mixing bowl, whisk together the dressing: soy sauce, olive oil, balsamic vinegar, honey, sesame oil and the finely grated garlic (garlic is optional).', 'Shred the romaine, finely chop the avocado, halve and finely slice the cucumber, finely slice the red onion and roughly chop the coriander.', 'Add the lettuce, avocado, cucumber, red onion, quinoa and coriander (if using) to the bowl and toss everything together. Divide between plates and flake the salmon over the top.']::text[], array['lunch', 'dinner']::text[], 2, 'Coriander and garlic in the dressing are optional. Use a veg peeler for cucumber ribbons if you prefer.', '', array['fish', 'quick', 'no-cook', 'summer']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Sweet Chilli Salmon Chopped Salad'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Teriyaki Salmon Noodles', 'A veg-packed noodle bowl with hot-smoked teriyaki salmon, sugar snaps and a mayo-lime dressing — on the table in 20 minutes.', null, '[{"id":"99a9cd9b-c438-4e48-bc1b-cb806014bc6a","name":"Sugar snap peas","quantity":160,"unit":"g"},{"id":"7c713d75-0f2c-4975-b825-45fdedd9d6f9","name":"Mayonnaise","quantity":3,"unit":"tbsp"},{"id":"061c107b-c0e2-4406-a33d-90ff274aeb42","name":"Soy sauce","quantity":1.5,"unit":"tbsp"},{"id":"01a0b0f0-2079-49cc-a511-855d16f3c9e3","name":"Lime","quantity":1,"unit":"pieces"},{"id":"c04a5248-b023-4f4c-8ac8-efddc4677d94","name":"Garlic cloves","quantity":1,"unit":"pieces"},{"id":"b936f9ea-6338-4004-98c4-4e949e02225c","name":"Microwaveable rice noodles","quantity":275,"unit":"g"},{"id":"51cf5d04-8dfe-4474-a0e3-1ab3a064a5d2","name":"White cabbage","quantity":150,"unit":"g"},{"id":"f10ebcad-9d4c-4d9f-8605-3a691354fce1","name":"Salad onions","quantity":4,"unit":"pieces"},{"id":"4baefbdd-129f-4445-884b-36b77187f42f","name":"Hot smoked salmon (teriyaki)","quantity":160,"unit":"g"},{"id":"f178bdc7-8743-4a1b-8772-3720a2eed93d","name":"Chilli oil","quantity":1,"unit":"tsp"}]'::jsonb,
       array['Bring a saucepan of salted water to the boil and blanch the sugar snaps for 2–3 minutes. Drain, refresh under cold running water and drain again. Meanwhile, in a large mixing bowl, whisk together the mayonnaise, soy sauce, lime juice and finely grated garlic.', 'Heat the rice noodles according to pack instructions, then add to the mixing bowl along with the finely shredded cabbage, finely sliced salad onions and sugar snaps. Toss everything together to coat in the dressing and divide between plates.', 'Remove the skin from the salmon and flake the fish over the noodles. Serve with a little chilli oil, if liked.']::text[], array['lunch', 'dinner']::text[], 2, 'Chilli oil is optional. Leftovers — use leftover white cabbage in a slaw with red onion and carrot, tossed with mayo and lemon juice.', '', array['fish', 'quick', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Teriyaki Salmon Noodles'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Sausage Bake with Chimichurri', 'A plant-based traybake of charlotte potatoes, red onion and pepper with meat-free sausages, finished with a zingy chimichurri.', null, '[{"id":"54fe2a16-0820-48cd-85c0-3219384b9aba","name":"Charlotte potatoes","quantity":700,"unit":"g"},{"id":"3487ccce-d81c-40a7-a058-b89db66aa1e9","name":"Olive oil","quantity":2,"unit":"tbsp"},{"id":"fb503ba8-d401-4654-82f7-97b4d0b18ac0","name":"Red onions","quantity":2,"unit":"pieces"},{"id":"6b3a04a0-a507-4962-b35d-f81dc344eba8","name":"Red pepper (large)","quantity":1,"unit":"pieces"},{"id":"528e2fef-96bc-419c-a291-6bb2575a0d88","name":"Sweet smoked paprika","quantity":0.5,"unit":"tsp"},{"id":"7ee8d4f5-27af-47a3-a8d2-172012672494","name":"Meat-free sausages","quantity":8,"unit":"pieces"},{"id":"9d5ed468-481f-4c17-b185-e0508c285bb1","name":"Spinach or kale","quantity":1,"unit":"bunch"},{"id":"e50d4653-51d1-4536-9c84-e310126123cc","name":"Chimichurri portions (frozen)","quantity":100,"unit":"g"}]'::jsonb,
       array['Preheat the oven to 200°C (gas mark 6). Cut the potatoes into bitesized pieces, toss with 1 tbsp of the oil on a large baking tray and roast for 15 minutes.', 'Cut the red onions into thin wedges and the red pepper into strips. Add to the tray with the remaining 1 tbsp oil, sprinkle over the paprika, season and stir everything together. Nestle the sausages into the tray and roast for 20 minutes, stirring halfway through.', 'Five minutes before the traybake is ready, toss through the spinach or kale (if using). At the same time, put the chimichurri portions in a microwaveable bowl, cover, and heat on full power for 2 minutes 30 seconds, stirring halfway through. Stand for 1 minute, then stir and serve with the sausages and vegetables.']::text[], array['dinner']::text[], 4, 'Spinach/kale is optional. Leftovers — chimichurri works with chicken or pork sausages too. The bake freezes for up to 2 months.', '', array['vegan', 'one-tray', 'midweek', 'family-favourite']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Sausage Bake with Chimichurri'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Miso Mushroom Noodles', 'A vegan wok supper ready in a flash, packed with umami miso, mushrooms and udon noodles. 2 of your 5-a-day.', null, '[{"id":"49330539-be5e-40c5-9ad6-6ad13d380232","name":"Sunflower oil","quantity":1,"unit":"tbsp"},{"id":"31a5f894-5927-4a10-a9e9-2a8062b1c2db","name":"Mushroom stir fry mix","quantity":400,"unit":"g"},{"id":"02c182ef-bdb7-451a-ac97-92e951c62290","name":"Udon noodles (straight-to-wok)","quantity":300,"unit":"g"},{"id":"86493aad-350f-4a35-8cc0-b77bf186a153","name":"White miso paste","quantity":2,"unit":"tbsp"},{"id":"6c594f56-0353-4f47-9d77-bd94b14ac458","name":"Balsamic vinegar","quantity":1,"unit":"tbsp"},{"id":"023a9756-8e93-4f3f-ad18-e925c2a924b7","name":"Maple syrup","quantity":1,"unit":"tbsp"},{"id":"eec5982a-a496-4585-ae88-acf90a815d07","name":"Soy sauce (reduced salt)","quantity":2,"unit":"tsp"},{"id":"7b3549ef-4d7a-4b4f-93be-8f52569398ee","name":"Toasted sesame oil","quantity":1,"unit":"tsp"},{"id":"b3d1695b-27d9-4f2d-8efd-86fb95748a75","name":"Garlic cloves","quantity":1,"unit":"pieces"}]'::jsonb,
       array['In a small bowl, mix the miso paste, balsamic vinegar, maple syrup, soy sauce, sesame oil and finely grated garlic with 2 tbsp water; set aside.', 'Heat the oil in a large wok or frying pan over a high heat. When smoking hot, add the mushroom stir fry and fry for 5 minutes, stirring regularly.', 'Add the miso sauce and the noodles and stir-fry for a final 2 minutes until everything is piping hot and coated in the sauce. Serve immediately.']::text[], array['dinner']::text[], 2, 'Leftovers — miso paste keeps in the fridge for up to 3 months. Use in glazes, marinades and salad dressings.', '', array['vegan', 'quick', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Miso Mushroom Noodles'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Balsamic Blueberry, Brie & Cavolo Nero Toasties', 'A grown-up toasted sandwich layering wilted cavolo nero, ripe brie and balsamic-poached blueberries on sourdough.', null, '[{"id":"c822e464-cfda-4e7f-a3a8-a2752f8883ef","name":"Blueberries","quantity":100,"unit":"g"},{"id":"ddc8a20c-b5ba-4d83-98da-08462dc39163","name":"Balsamic vinegar","quantity":2,"unit":"tbsp"},{"id":"e082c062-b232-4490-8745-a39815da1794","name":"Rosemary","quantity":1,"unit":"bunch"},{"id":"5ff8bb21-7ef9-4b50-a02b-d8ee43974e1d","name":"Olive oil","quantity":1,"unit":"tsp"},{"id":"f2a811e1-bbb1-4f4a-b442-2fc7d6a015ca","name":"Garlic cloves","quantity":1,"unit":"pieces"},{"id":"7fbec47b-b3e9-4a60-a96e-27a703416a53","name":"Cavolo nero","quantity":100,"unit":"g"},{"id":"66beb144-7637-449d-b044-10f92fae91d1","name":"Sourdough bread (large slices)","quantity":4,"unit":"pieces"},{"id":"b4d984ac-9833-4150-8aae-4dc762f50a4c","name":"Unsalted butter","quantity":15,"unit":"g"},{"id":"938184ff-c750-4a3c-b401-3dae463e48ab","name":"Wholegrain mustard","quantity":1,"unit":"tbsp"},{"id":"c32a764b-de4a-45cb-adaf-dc97467ab4a3","name":"Ripe brie","quantity":100,"unit":"g"}]'::jsonb,
       array['Put the blueberries, balsamic vinegar and a sprig of rosemary in a small saucepan. Heat gently until just bubbling, then remove from the heat and set aside. Meanwhile, heat the oil in a large frying pan over a medium heat. Add the peeled and bashed garlic, cavolo nero (stalks removed, leaves cut into strips), 1 tbsp water and a pinch of salt, and fry for about 3–4 minutes, turning regularly, until wilted. Tip onto a plate. Leave the pan ready for the sandwiches.', 'Spread one side of each slice of bread with butter — these will be the outsides. Spread two of the inside slices with mustard, then layer up with the cavolo nero, sliced brie and finally the balsamic blueberries (discarding the rosemary). Top with the remaining slices of sourdough (butter on the outside) and press down lightly.', 'Return the frying pan to a medium-high heat. Add the sandwiches, cover with a sheet of parchment, then top with another frying pan weighed down with 2 cans of beans. Fry for 3 minutes, then carefully turn and fry for another 3 minutes. Remove, cool for a minute, then halve and serve.']::text[], array['lunch']::text[], 4, 'Cook''s tip — poaching blueberries with balsamic brings out a richer flavour. Make a double batch and enjoy the leftovers over vanilla ice cream.', '', array['vegetarian', 'sandwich', 'winter']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Balsamic Blueberry, Brie & Cavolo Nero Toasties'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Chipotle Bean & Avocado Tacos', 'Quick, smoky black-bean tacos with lime-dressed red cabbage, avocado and melty cheddar. Ready in 20 minutes.', null, '[{"id":"1c60167f-e0d1-438a-8707-e132ea006895","name":"Vegetable oil","quantity":2,"unit":"tbsp"},{"id":"29ac8301-b8e0-4376-9df5-f5091309a911","name":"Red onion","quantity":1,"unit":"pieces"},{"id":"a2de7a83-207e-42de-8c9f-1b07ec40b576","name":"Garlic cloves","quantity":1,"unit":"pieces"},{"id":"6623d021-72ac-43f7-bee8-5ccdebe5930f","name":"Black beans (tinned)","quantity":1,"unit":"tin"},{"id":"e87c27ec-a60a-4275-b5ed-caf4c3dcfd6d","name":"Chipotle paste","quantity":1,"unit":"tsp"},{"id":"bd4fb186-0c93-441e-b559-fa64f8d3e109","name":"Red cabbage","quantity":0.25,"unit":"pieces"},{"id":"5d01dc1c-151d-4a3e-b438-41700a9396a9","name":"Lime","quantity":1,"unit":"pieces"},{"id":"7dd7132f-06ba-418e-b5d3-6bcf5260b421","name":"Soft taco wraps","quantity":6,"unit":"pieces"},{"id":"f457000d-5138-4a92-8c24-05fa804bc482","name":"Avocado","quantity":1,"unit":"pieces"},{"id":"aca6e72b-8f02-4b78-aa3f-92814ee07be3","name":"Mature cheddar","quantity":60,"unit":"g"}]'::jsonb,
       array['Heat 1½ tbsp of the oil in a saucepan over a medium heat. Fry the finely chopped red onion, crushed garlic and a pinch of salt for 5 minutes until starting to soften. Add the drained and rinsed black beans, chipotle paste and 100 ml water and cook for another 5 minutes. Lightly crush the beans with a potato masher, leaving some whole, to create a thick sauce.', 'Meanwhile, toss the finely shredded cabbage with the remaining ½ tbsp oil, the juice of ½ the lime and a pinch of salt. Warm the taco wraps according to pack instructions and divide between plates or a platter.', 'Top the tacos with the beans, a little red cabbage, the sliced avocado and the grated cheese. Serve with the remaining lime cut into wedges.']::text[], array['dinner']::text[], 2, 'Leftovers — chipotle paste is great spread on chicken or salmon before grilling, or stirred into chilli con carne for a kick.', '', array['vegetarian', 'quick', 'mexican', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Chipotle Bean & Avocado Tacos'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Summery Pea & Basil Soup', 'A vivid green soup of leeks, peas and basil, finished with crème fraîche. Great as a quick lunch with crusty bread and soft goat''s cheese.', null, '[{"id":"6aa000d6-bc07-42af-9fa0-1fb2e01f462c","name":"Olive oil","quantity":2,"unit":"tbsp"},{"id":"065c0399-0ffe-4a2c-b05e-d7a8a46a8657","name":"Leeks (large, ~400g total)","quantity":2,"unit":"pieces"},{"id":"1d015c80-ff77-4460-818f-6ab6c5162935","name":"Garlic cloves","quantity":1,"unit":"pieces"},{"id":"01b804d3-686c-4cd8-8208-2052991a7bd9","name":"Garden peas (frozen)","quantity":400,"unit":"g"},{"id":"42eded2c-6e64-4db9-89bb-ad508c00200a","name":"Vegetable stock (low-salt)","quantity":750,"unit":"ml"},{"id":"f94326a5-8fda-4974-9935-c8196ce94735","name":"Basil","quantity":12,"unit":"g"},{"id":"13ae11fc-57c8-48d6-9a2d-68e7d7474491","name":"Crème fraîche","quantity":3,"unit":"tbsp"},{"id":"c03b9f35-e7d4-4c0f-a7a3-1c761308da8b","name":"Lemon","quantity":0.5,"unit":"pieces"}]'::jsonb,
       array['Heat the oil in a large frying pan over a medium heat. Add the trimmed and sliced leeks and a pinch of salt. Fry for 5–6 minutes until soft, then add the finely sliced garlic and fry for 2–3 minutes more. Add the peas and stock, bring to a simmer and cook for a further 3–4 minutes. Take off the heat and allow to cool for 5 minutes.', 'Add the basil (about 30 leaves), crème fraîche and a squeeze of lemon juice (if using) to the pan; season. Whizz with a stick blender (or use a jug blender) until smooth. Taste and adjust the seasoning.', 'Reheat if needed, then divide between bowls. Top with a little more crème fraîche, a few basil leaves and a grinding of black pepper.']::text[], array['lunch']::text[], 4, 'Lemon juice is optional. The soup freezes for up to 3 months. Cook''s tip — for a plant-based version, swap the crème fraîche for a non-dairy alternative (e.g. Oatly oat fraîche).', '', array['vegetarian', 'soup', 'quick', 'batch-cook', 'summer']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Summery Pea & Basil Soup'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Chickpea & Mushroom Pasta', 'A creamy, garlicky vegan pasta with chestnut mushrooms, chickpeas and a lemony nutritional-yeast cream sauce. Under 30 minutes.', null, '[{"id":"575cfa71-5d35-4684-a4ce-6a19981405a7","name":"Vegan butter","quantity":50,"unit":"g"},{"id":"1e10f237-98c9-4f9c-b95c-547deff3924b","name":"Garlic cloves","quantity":4,"unit":"pieces"},{"id":"89a2fca1-ac91-42dc-a7a8-1aa7c130733b","name":"Chestnut mushrooms","quantity":250,"unit":"g"},{"id":"43c9611c-f690-471e-9c8d-22edb1294726","name":"Spaghetti","quantity":350,"unit":"g"},{"id":"def1920f-9a18-410d-9a57-351c8de180b3","name":"Chickpeas (tinned)","quantity":1,"unit":"tin"},{"id":"0d71e349-471f-4f8f-8d7e-4f342b9f795b","name":"Vegan cream cheese","quantity":200,"unit":"g"},{"id":"0cd0db75-e1cb-43fc-b489-e6f081a6fffc","name":"Nutritional yeast","quantity":2,"unit":"tbsp"},{"id":"70e975c9-c98e-4e25-b882-037771f36fcd","name":"Unwaxed lemon","quantity":1,"unit":"pieces"},{"id":"b3452efd-51ca-431d-9726-3d28737f42ee","name":"Flat leaf parsley","quantity":12,"unit":"g"}]'::jsonb,
       array['Heat the vegan butter in a large frying pan over a medium-high heat. Add the crushed or finely grated garlic and fry for 1 minute. Add the thickly sliced mushrooms and a pinch of salt and fry for 2 minutes. Meanwhile, bring a large saucepan of salted water to the boil, add the pasta and cook for 1 minute less than pack instructions.', 'Add the drained and rinsed chickpeas to the pan with the mushrooms and fry for 6–7 minutes until the mushrooms have released their liquid and are starting to colour. Meanwhile, mix the vegan cream cheese in a bowl with the nutritional yeast, lemon zest, some ground black pepper and 5 tbsp of cooking water from the pasta pan.', 'Drain the pasta, reserving a little cooking water. Tip the pasta into the frying pan with the mushrooms and chickpeas. Add 3 tbsp of the reserved cooking water and stir over the heat. Take off the heat and stir through the creamy mixture and the juice of ½ the lemon. Season and toss with the chopped parsley before serving with extra black pepper.']::text[], array['dinner']::text[], 4, 'Cook''s tip — nutritional yeast has a deeply savoury, almost cheesy flavour. It''s a savvy vegan alternative to parmesan or pecorino; use it in soups, risottos, dressings and dips.', '', array['vegan', 'pasta', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Chickpea & Mushroom Pasta'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Beetroot & Goat''s Cheese Salad', 'A make-a-meal-of-it salad layering roasted beetroot, beluga lentils, red chicory, fresh herbs and goat''s cheese pearls.', null, '[{"id":"e7381a39-8d55-433d-abd7-af3b21def689","name":"Bunched beetroot","quantity":500,"unit":"g"},{"id":"0f3db574-e989-43f0-be1d-29535af6051b","name":"Olive oil (extra virgin)","quantity":5,"unit":"tbsp"},{"id":"7d85e4df-5563-4c7c-9e26-bd46f0ad05b2","name":"Cooked beluga lentils","quantity":500,"unit":"g"},{"id":"2f83fe65-d3dc-4a6f-b303-876e29a9ec66","name":"Balsamic vinegar","quantity":2,"unit":"tbsp"},{"id":"6630fb9f-4479-405b-bbbd-71c7487eaf88","name":"Clear honey","quantity":1,"unit":"tsp"},{"id":"938344f4-9035-420b-afe0-54944515d30e","name":"Red chicory","quantity":140,"unit":"g"},{"id":"8f6b5924-d41d-42c6-83cc-f634d14ef8b7","name":"Chives","quantity":20,"unit":"g"},{"id":"92b9147b-252c-46c4-a883-e85e5c5b234a","name":"Mint","quantity":12,"unit":"g"},{"id":"93eaa969-105f-47c2-9da7-c476cd5d26b6","name":"Goat''s cheese pearls","quantity":200,"unit":"g"}]'::jsonb,
       array['Preheat the oven to 200°C (gas mark 6). In a bowl, toss the peeled beetroot wedges (cut into 2 cm pieces) with 1 tbsp of the oil, season and spread over a large baking tray. Roast for 20 minutes, then stir and roast for another 15 minutes. Add the lentils to the tray with 1 tbsp oil, season and roast for a final 10 minutes. Leave to cool for 5 minutes.', 'Meanwhile, mix 2 tbsp of the oil in a large bowl with the balsamic vinegar and honey; season. Add the cooked beetroot and lentils, then stir in the roughly chopped chicory and most of the chopped chives and shredded mint. Stir through most of the goat''s cheese.', 'To serve, scatter over the remaining goat''s cheese and herbs, then drizzle over the remaining 1 tbsp oil.']::text[], array['lunch', 'dinner']::text[], 4, 'Simple swap — beluga lentils can be replaced with brown or puy. To speed things up, use ready-cooked beetroot and just roast with the lentils for 10 minutes to warm through.', '', array['vegetarian', 'salad', 'healthy']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Beetroot & Goat''s Cheese Salad'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Cheesy Lemon Spaghetti', 'A zingy weeknight winner ready in 15 minutes, made with just a handful of simple ingredients: butter, garlic, lemon and parmesan.', null, '[{"id":"1eb61a57-58a3-4670-b5db-e5e92af1c51b","name":"Spaghetti","quantity":180,"unit":"g"},{"id":"e71a80d8-25e8-43cb-bcba-1c5762582708","name":"Unsalted butter","quantity":40,"unit":"g"},{"id":"dd86df81-3027-4ea4-8d6e-f49a1ddec347","name":"Garlic cloves","quantity":1,"unit":"pieces"},{"id":"f6669b0a-a147-463f-be60-4cdbb4c44730","name":"Unwaxed lemon","quantity":1,"unit":"pieces"},{"id":"f6660af6-c166-4c7e-9677-9276da81878c","name":"Parmigiano Reggiano","quantity":30,"unit":"g"},{"id":"292df7fb-ca24-40eb-8e3b-fce9052759b2","name":"Flat leaf parsley","quantity":2,"unit":"tbsp"}]'::jsonb,
       array['Bring a large pan of salted water to the boil. Add the spaghetti and cook for 1 minute less than pack instructions.', 'About 4 minutes before the spaghetti is ready, melt the butter in a large frying pan over a medium heat. When foaming, add the finely chopped garlic, half the lemon zest and a pinch of salt. Fry, stirring, for 2–3 minutes until the garlic is just golden.', 'Drain the spaghetti and add to the frying pan with the juice of ½ the lemon and most of the parmesan. Toss together to emulsify the sauce, then add the chopped parsley. Serve with the remaining lemon zest and parmesan sprinkled over, and a few grindings of black pepper.']::text[], array['dinner']::text[], 2, 'Cook''s tip — add a sprinkle of chilli flakes for a burst of heat.', '', array['vegetarian', 'pasta', 'quick', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Cheesy Lemon Spaghetti'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Crispy Sea Bass with Lentils', 'Pan-fried sea bass on a bed of caramelised fennel, red onion and capers stirred through warm lentils. Super-speedy and gluten-free.', null, '[{"id":"430012f0-1d27-41eb-8a17-dfda1c06c8d9","name":"Olive oil","quantity":2,"unit":"tbsp"},{"id":"b6c8d123-ce5b-460e-9578-a703cf80ee16","name":"Fennel bulb (large, ~160g)","quantity":1,"unit":"pieces"},{"id":"826c6b8e-1700-4451-bd93-731a5fa033c4","name":"Red onion","quantity":1,"unit":"pieces"},{"id":"5662e0c7-d193-4702-abd6-f2b5e57b83bc","name":"Nonpareille capers","quantity":1,"unit":"tbsp"},{"id":"43baca49-dd1d-4186-8be9-fd9f5484100d","name":"Lentils (tinned, in water)","quantity":1,"unit":"tin"},{"id":"4fdf77d8-479a-4353-916b-cc0b91a21948","name":"Lemon","quantity":0.5,"unit":"pieces"},{"id":"47048a08-e486-406d-8b7d-5bdfb80ee7f4","name":"Sea bass fillets","quantity":2,"unit":"pieces"}]'::jsonb,
       array['Heat 1 tbsp of the oil in a frying pan over a medium heat. Trim the fennel (reserving the fronds), remove the core and finely slice. Add to the pan with the finely sliced red onion, drained and rinsed capers, and a pinch of salt. Cook, stirring regularly, for 8–10 minutes until the vegetables are soft, lightly golden and caramelised.', 'Add the drained and rinsed lentils to the pan with ½ tbsp oil and the juice of ¼ of the lemon. Heat through until piping hot, season and divide between plates.', 'Wipe out the pan and return to the heat with the remaining ½ tbsp oil. Pat the sea bass dry with kitchen paper, score the skin 5–6 times and season all over. Fry, skin-side down, in the hot oil for 3 minutes until the skin is golden and releases easily from the pan. Turn and cook on the flesh side for 2–3 minutes, until opaque and flaking easily.', 'Serve the sea bass with the lentils, reserved fennel fronds scattered on top, and the remaining ¼ of the lemon cut into wedges for squeezing over.']::text[], array['dinner']::text[], 2, 'Cook''s tip — these fillets can also be grilled (just make sure they''re fully cooked and flake easily). Try serving with steamed veg and a coconut curry sauce for a different spin.', '', array['fish', 'quick', 'midweek', 'gluten-free', 'healthy']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Crispy Sea Bass with Lentils'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Thai Basil & Aubergine Curry', 'A fragrant Thai red curry with roasted aubergine wedges, coconut milk and lots of fresh Thai basil. Add prawns or tofu for extra protein.', null, '[{"id":"f53d2c54-5c60-431f-a247-03ee8c6bdcfc","name":"Aubergines","quantity":2,"unit":"pieces"},{"id":"f354feec-2557-4ed2-8917-ae68b8d874bd","name":"Sunflower oil","quantity":2.5,"unit":"tbsp"},{"id":"f5b66f15-c16f-48bc-a79e-319f40bc3360","name":"Echalion shallots","quantity":1,"unit":"pieces"},{"id":"7aaf7be7-b7bd-4d29-ab7e-c30813783262","name":"Garlic cloves","quantity":1,"unit":"pieces"},{"id":"55d055ea-eeff-4e51-bbdc-0e4ebabb2a62","name":"Thai red curry paste","quantity":3,"unit":"tbsp"},{"id":"434545d7-ad4c-49e1-9e85-176b1a704d74","name":"Coconut milk (reduced fat)","quantity":1,"unit":"tin"},{"id":"37c35910-d1c0-4489-8bed-3b9b04543138","name":"Makrut lime leaves (fresh)","quantity":4,"unit":"pieces"},{"id":"60ef8502-570a-4ea6-ab3b-1c892b126d23","name":"Fish sauce (nam pla)","quantity":1,"unit":"tbsp"},{"id":"821a1049-dc72-4cd4-9ee0-0530117c943b","name":"Caster sugar","quantity":1,"unit":"tsp"},{"id":"5845e173-c6a9-4bfd-9c96-20a58d9ca200","name":"Lime","quantity":0.5,"unit":"pieces"},{"id":"45c23354-7675-4ba3-ad5a-36a6087b654d","name":"Thai basil","quantity":20,"unit":"g"}]'::jsonb,
       array['Preheat the oven to 220°C (gas mark 7). Line a large baking tray with foil. Cut the aubergines lengthways into slim wedges. Toss with 2 tbsp of the oil and spread over the lined tray. Season and roast for 30 minutes, turning halfway, until golden.', 'Meanwhile, heat the remaining ½ tbsp oil in a large saucepan over a medium-high heat. Fry the finely sliced shallot and garlic for 2–3 minutes, then add the curry paste and stir over the heat for 1–2 minutes (it will spit a bit — take care). Stir in the coconut milk, scrunched lime leaves, fish sauce, sugar and lime juice. Simmer gently for 5–10 minutes, stirring in three-quarters of the Thai basil for the last minute.', 'Divide the aubergines between bowls with steamed rice noodles or jasmine rice, if liked. Spoon over the sauce (discarding the lime leaves) and scatter with the remaining Thai basil and some roasted cashews or peanuts, if liked.']::text[], array['dinner']::text[], 2, 'Ahead of the game — the curry sauce can be made up to 48 hours ahead. Cover and chill, then reheat to serve; leave the lime leaves in to infuse if doing this. Add cooked prawns or tofu for protein.', '', array['vegan', 'curry', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Thai Basil & Aubergine Curry'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Ginger & Turmeric Cod with Rice Noodles', 'A fast Vietnamese-inspired fish supper of marinated cod, dill, beans and onion over rice vermicelli, with a sweet-sharp lime-chilli sauce.', null, '[{"id":"34dc583a-a197-498d-88cc-0a640dcfeef4","name":"Fish sauce","quantity":2,"unit":"tbsp"},{"id":"b4c11baf-b305-4c26-a2ed-2150e07fed1d","name":"Clear honey","quantity":4,"unit":"tsp"},{"id":"dac98a1f-84ab-4048-b611-aa00aa051195","name":"Ginger","quantity":2,"unit":"tsp"},{"id":"673b29b0-71eb-46b3-91a1-07d2abb7e756","name":"Ground turmeric","quantity":0.5,"unit":"tsp"},{"id":"08a0b50b-e0bf-4550-9b75-ac52f8dbebdb","name":"Cod fillets","quantity":2,"unit":"pieces"},{"id":"70f46b91-39ff-44fb-8e80-4430f19a4536","name":"Rice vermicelli noodles","quantity":100,"unit":"g"},{"id":"f57073c2-df02-48b0-8c64-c263da2e8316","name":"Lime juice","quantity":1,"unit":"tbsp"},{"id":"03b44447-e459-4ef7-b590-a46314382f92","name":"Red chilli","quantity":1,"unit":"pieces"},{"id":"0cbe130e-80e2-4c39-a3a2-3032ad25e2d0","name":"Sunflower oil","quantity":1.5,"unit":"tbsp"},{"id":"3f6e74d1-ae88-4c1d-8c2b-79a914738d68","name":"Onion","quantity":1,"unit":"pieces"},{"id":"ec94a433-af4f-433e-a8b7-0169593e5c16","name":"Garlic cloves","quantity":2,"unit":"pieces"},{"id":"c88dcf09-758f-4a6e-bc40-990629f84e4b","name":"Round green beans","quantity":120,"unit":"g"},{"id":"5ed4d4fb-d62c-471b-b24d-a341f372b901","name":"Dill","quantity":10,"unit":"g"}]'::jsonb,
       array['In a mixing bowl, whisk together 1 tbsp of the fish sauce, 2 tsp of the honey, the grated ginger, turmeric and a grinding of black pepper. Add the cod fillets, coating them in the mixture, then cover and set aside for 15 minutes.', 'Meanwhile, soak the noodles in just-boiled water for 8 minutes, then drain. Rinse with lukewarm water and toss with a splash of oil to prevent sticking. Shake off as much water as possible and divide between two plates.', 'In a small bowl, mix the lime juice with the remaining 1 tbsp fish sauce, 2 tsp honey and the finely chopped red chilli.', 'Heat 1 tbsp of the oil in a large non-stick frying pan over a medium-high heat. Fry the thinly sliced onion, crushed garlic and trimmed and halved beans for 8 minutes until tender and just golden. Scoop into a bowl. Return the pan to a high heat with the remaining ½ tbsp oil and fry the fish for 2 minutes on each side (don''t worry if it breaks up a little). Return the vegetables to the pan with the roughly chopped dill and heat for a final minute, ensuring the fish is opaque and flakes easily. Pile everything onto the noodles, spoon over the sauce and serve at once.']::text[], array['dinner']::text[], 2, 'Cook''s tip — based on the Vietnamese dish Cha Ca La Vong. Sprinkle over roasted peanuts for extra flavour and crunch.', '', array['fish', 'quick', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Ginger & Turmeric Cod with Rice Noodles'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Honey Smoked Salmon Linguine', 'Linguine in a creamy spinach-and-lemon sauce, finished with strips of honey-smoked Scottish salmon stirred through the residual heat.', null, '[{"id":"6629c815-15f9-4c3f-8b64-9a41ae2e13cf","name":"Unsalted butter","quantity":30,"unit":"g"},{"id":"679fef08-80a9-485b-aec0-474269bf2b53","name":"Shallot","quantity":1,"unit":"pieces"},{"id":"68a46b26-5930-4695-a4b3-1fd2a140a03e","name":"Dried linguine","quantity":180,"unit":"g"},{"id":"cc4b813b-ca6a-487b-835b-a83bb564b6e2","name":"Coriander seeds","quantity":0.5,"unit":"tsp"},{"id":"7f309665-4613-481e-9428-351919bf8c3d","name":"Unwaxed lemon","quantity":1,"unit":"pieces"},{"id":"c76f6457-b90d-40ae-9f3f-78e03cbe2a60","name":"Spinach","quantity":160,"unit":"g"},{"id":"b8549b2a-fd3a-48e4-a46e-62d5286b6782","name":"Double cream","quantity":3,"unit":"tbsp"},{"id":"35982857-ca5e-4f53-8ca9-751c11cf3703","name":"Honey smoked salmon","quantity":100,"unit":"g"},{"id":"57e471fd-8a5b-483c-8ba7-bd2ab95c3583","name":"Pecorino","quantity":20,"unit":"g"}]'::jsonb,
       array['Bring a large pan of salted water to the boil. Meanwhile, heat the butter in a separate large pan over a medium heat. Add the finely chopped shallot with a pinch of salt and fry for 5 minutes until soft. Once the water is boiling, add the linguine and cook for a minute less than pack instructions. Drain, reserving a mug of pasta water.', 'Meanwhile, if using, crush the coriander seeds in a pestle and mortar and tip into the pan with the shallot. Add the lemon zest and fry for 1–2 minutes. Add the spinach and cook, stirring, until wilted (2–3 minutes), then stir in the cream and 1–3 tbsp of the reserved pasta water. Cook over the heat for 1 minute.', 'Add the linguine to the creamy spinach sauce, stirring everything together over the heat for 1 minute until nicely coated. Take the pan off the heat, grind over some black pepper and stir through the salmon (cut into strips) so it just warms in the residual heat. Serve with lemon wedges and a little grated pecorino, if liked.']::text[], array['dinner']::text[], 2, 'Cook''s tip — cooking pasta a minute less than the pack says lets it finish in the sauce, absorbing extra flavour. Coriander seeds and pecorino are optional. Add a splash of white wine to the sauce if you''re enjoying a glass with the meal.', '', array['fish', 'pasta', 'quick', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Honey Smoked Salmon Linguine'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Salmon & Chilli Noodles', 'A satisfying stir-fry with bashed cucumber, hot-smoked honey salmon, fine egg noodles and a sesame-soy dressing finished with chilli sea salt.', null, '[{"id":"00f7e357-2c76-4796-b279-b31dda95f1e1","name":"Cucumber","quantity":250,"unit":"g"},{"id":"6967df82-3e09-459d-93f4-ea8799d2d2c2","name":"Fine egg noodles","quantity":125,"unit":"g"},{"id":"00c36fac-a1d2-465f-9ac0-2002ff0f531b","name":"Salad onions","quantity":2,"unit":"pieces"},{"id":"26ec75b4-8c41-4cfb-97a7-7d47a4a2b397","name":"Hot smoked salmon (honey)","quantity":216,"unit":"g"},{"id":"0c2bf2bb-f8be-4db9-8193-0c3eac2e9e9f","name":"Chilli sea salt","quantity":0.5,"unit":"tsp"},{"id":"867a6621-f2c1-4118-813b-feb716c31155","name":"Rice vinegar","quantity":2,"unit":"tbsp"},{"id":"4d1f7bea-2e08-488b-8db9-4552612ad9b1","name":"Soy sauce (reduced salt)","quantity":1.5,"unit":"tbsp"},{"id":"045ef5f3-50f9-4c11-be9a-a2d0c7b425d9","name":"Toasted sesame oil","quantity":2,"unit":"tsp"},{"id":"4f1014cd-854c-45e7-a9f3-842c0fe2579b","name":"Garlic cloves","quantity":1,"unit":"pieces"},{"id":"c418fd68-dc87-4eaf-bf5b-c2607c6268d2","name":"Clear honey","quantity":0.5,"unit":"tsp"}]'::jsonb,
       array['Bring a large saucepan of salted water to the boil. In a large bowl, whisk together the dressing: rice vinegar, soy sauce, sesame oil, finely grated garlic and honey. Halve the cucumber lengthways and put cut-side down on a chopping board, then bash with a rolling pin so it cracks in places. Roughly chop and tip into the dressing; toss together. Set aside until ready to serve.', 'Add the noodles to the pan of boiling water, then take off the heat and leave to stand for 5 minutes. Drain in a sieve, rinse briefly under cold water and shake dry. Tip into the bowl with the cucumber and dressing. Add the finely sliced salad onions and toss everything together.', 'Divide the noodles and cucumber between 2 plates or shallow bowls and top with the roughly flaked salmon. Scatter with chilli sea salt and serve.']::text[], array['lunch', 'dinner']::text[], 2, 'Swap the salmon for smoked tofu to keep it veggie. Leftovers — chilli sea salt is good sprinkled on grilled chicken, sweet potato wedges, or tropical fruits like mango or pineapple.', '', array['fish', 'quick', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Salmon & Chilli Noodles'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Carrot & Cheese Fritter Pittas', 'Moreish carrot and halloumi fritters tucked into pittas with chickpeas, fresh herbs, cherry tomatoes, sliced egg and a tahini-lime dressing.', null, '[{"id":"75e1bd1f-15bc-4127-863f-681c86fd77bc","name":"Red onion (small)","quantity":1,"unit":"pieces"},{"id":"789827cc-f75a-4f9e-bab9-2b471cffa485","name":"Carrots","quantity":250,"unit":"g"},{"id":"dfaf8543-b91d-4f39-a675-904cd29ac9a3","name":"Halloumi (Cypriot grilling cheese)","quantity":250,"unit":"g"},{"id":"d8d2db9f-a7f8-45e2-b54c-a6e460e8d2d3","name":"Cumin seeds","quantity":2,"unit":"tsp"},{"id":"6fa9ffe9-7bca-409d-b68a-49848b5b78dd","name":"Gram (chickpea) flour","quantity":125,"unit":"g"},{"id":"99aea0a1-2adf-4d76-b105-4d0f6244b101","name":"Salt","quantity":0.25,"unit":"tsp"},{"id":"7dd54e5b-c3f4-4823-832e-80b559d792d0","name":"Unwaxed limes","quantity":2,"unit":"pieces"},{"id":"125e02a2-b781-4b68-82ef-f0cd662ccf65","name":"Coriander","quantity":25,"unit":"g"},{"id":"2d1aab3f-cfc9-4aa4-a5b5-e8bb914c80ff","name":"Chickpeas (tinned)","quantity":1,"unit":"tin"},{"id":"7b94fec6-01d9-4120-95ba-8bc93c16152e","name":"Vegetable oil (for frying)","quantity":100,"unit":"ml"},{"id":"670b1565-dd5d-46f2-aa74-f75b467d2256","name":"Free range eggs (medium)","quantity":4,"unit":"pieces"},{"id":"76bd1d5e-5e89-495f-ac88-7726eed83dc7","name":"Pitta breads","quantity":6,"unit":"pieces"},{"id":"a56e7226-8452-4601-b26c-169a688a3520","name":"Tahini","quantity":2,"unit":"tbsp"},{"id":"6d2e7491-72c4-4763-b441-6ddd2997bedb","name":"Cherry tomatoes","quantity":100,"unit":"g"}]'::jsonb,
       array['Finely slice one quarter of the red onion and set aside. Finely chop the rest and add to a large mixing bowl with the coarsely grated carrots and halloumi, cumin seeds, gram flour, salt, the zest and juice of 1 lime and half of the roughly chopped coriander. Crush the drained chickpeas with the back of a fork and add to the bowl, then mix thoroughly.', 'Heat the oil in a large frying pan over a medium-high heat. Take small handfuls of the mixture (about 75 g each) and press together to make 12 patties, squeezing quite firmly. Add to the hot oil in batches, press down with a spatula and cook for 4–5 minutes on each side until golden, crisp and piping hot throughout. Lift onto a kitchen-paper-lined plate.', 'Meanwhile, bring a small pan of water to the boil, lower in the eggs and cook for 8 minutes. Plunge into cold water, then peel and slice. Toast the pittas. Mix the tahini with the juice of the second lime and a pinch of salt, then add 2–4 tbsp water to make a smooth sauce.', 'To serve, put 2 fritters in each pitta with the quartered cherry tomatoes, sliced red onion, sliced egg, the remaining coriander and a drizzle of the tahini dressing.']::text[], array['lunch', 'dinner']::text[], 6, 'Cook''s tip — gram (chickpea) flour has a nutty flavour and is widely used in pakoras, bhajis, gluten-free pancakes and falafel.', '', array['vegetarian', 'sandwich', 'midweek', 'family-favourite']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Carrot & Cheese Fritter Pittas'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Goan Fish Curry', 'Gymkhana''s quick Goan fish curry — cod fillets marinated in roasted garlic & chilli, seared until golden, then simmered in a coconut Goan curry sauce and finished with a curry-leaf and red chilli tadka.', null, '[{"id":"067a445c-37ea-4056-96fc-200b0342cdcc","name":"Goan curry cooking sauce (jar)","quantity":1,"unit":"pack"},{"id":"1f82f4e6-02ca-4eb7-93c7-f2c94974660e","name":"Roasted garlic & chilli marinade (jar)","quantity":1,"unit":"pack"},{"id":"bde52bb7-7227-4ed6-9483-cd1209506fd9","name":"Cod fillets","quantity":2,"unit":"pieces"},{"id":"eb402963-ac4d-4d10-b163-3f974178b089","name":"Ground turmeric","quantity":0.25,"unit":"tsp"},{"id":"a82f6811-5608-4e28-bdc9-f0fdf991ed6b","name":"Chilli powder","quantity":0.25,"unit":"tsp"},{"id":"1ccf2cfd-b259-432c-b8c1-de827771082e","name":"Salt","quantity":0.25,"unit":"tsp"},{"id":"c9a14e4f-bb4b-4967-b6da-b581d667a4c4","name":"Curry leaves","quantity":2,"unit":"g"},{"id":"99b52c3a-dfe9-4cda-81e9-7c5ae954b951","name":"Red chillies","quantity":2,"unit":"g"},{"id":"3e46c7c6-a01c-4e48-bdf7-f691d0b3548c","name":"Mustard seeds","quantity":1,"unit":"tsp"},{"id":"17277e84-b70a-492a-bf5c-8afeb13a4dd6","name":"Vegetable oil","quantity":1,"unit":"tbsp"}]'::jsonb,
       array['Marinate the cod fillets in the roasted garlic & chilli marinade with the turmeric, chilli powder and salt for 15–20 minutes.', 'Heat the oil in a pan and sear the cod fillets skin-side down for 6 minutes, or until golden, then turn and cook for a further 4 minutes until the fish is cooked through.', 'Add the Goan curry sauce and simmer for 6–8 minutes.', 'Serve with a tadka of mustard seeds, curry leaves and chopped red chillies.']::text[], array['dinner']::text[], 2, 'Uses Gymkhana Fine Foods'' jarred Goan curry cooking sauce and roasted garlic & chilli marinade. Swap the cod for another firm white fish, salmon or prawns if you prefer. Serve with steamed basmati rice.', 'https://www.gymkhanafinefoods.com/blogs/recipe/goan-fish-curry', array['fish', 'curry', 'quick', 'midweek']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Goan Fish Curry'
);

insert into recipes
  (household_id, title, description, image, ingredients, steps, meal_type, servings, notes, source_url, tags)
select null, 'Salmon Poke Bowl', 'A fresh, no-cook bowl of smoked salmon over rice with avocado, edamame, cucumber, pickled ginger and a quick spicy mayo — with optional mango for a sweet note.', null, '[{"id":"b0196f0c-b476-40af-97b8-46db8b35f6b5","name":"Smoked salmon slices","quantity":150,"unit":"g"},{"id":"8ac285b0-d81b-4fab-90b8-fe76f776c9e7","name":"Soy sauce (reduced salt)","quantity":2,"unit":"tbsp"},{"id":"e317e37f-ac4b-4cc3-8e43-8dca5ef444fa","name":"Toasted sesame oil","quantity":1,"unit":"tsp"},{"id":"5a676a7a-0dcf-436f-80d6-f588a402a597","name":"Rice vinegar","quantity":1,"unit":"tbsp"},{"id":"7f14f6b4-e9a0-4c24-a28b-d03247a512c0","name":"Clear honey","quantity":1,"unit":"tsp"},{"id":"f0a1bb88-8fb1-4b72-ab15-f14c176e51fe","name":"Sushi or short-grain rice","quantity":150,"unit":"g"},{"id":"6444d8da-e377-4215-8b26-f0e18bc43830","name":"Edamame beans (frozen)","quantity":100,"unit":"g"},{"id":"a05e0793-043e-4255-b5dd-9d335ffd8463","name":"Avocado","quantity":1,"unit":"pieces"},{"id":"b5ca7c0f-791b-4359-9b78-a02f971b84bd","name":"Cucumber","quantity":150,"unit":"g"},{"id":"c263c71f-d061-449e-95ad-90a145ec2fb7","name":"Salad onions","quantity":2,"unit":"pieces"},{"id":"a6904218-91c4-46a5-8bbe-86581290947e","name":"Pickled ginger","quantity":30,"unit":"g"},{"id":"80669d77-f0e0-4439-bf6d-5fe57e7ed64c","name":"Mango","quantity":0.5,"unit":"pieces"},{"id":"b579575c-a866-4ce9-947d-0f1ab48d05f0","name":"Mayonnaise","quantity":2,"unit":"tbsp"},{"id":"d0a41731-4e2e-4b47-877e-41dda1c86d00","name":"Sriracha","quantity":1,"unit":"tsp"},{"id":"72d21872-0dd2-46a9-bd82-82b82897ea10","name":"Sesame seeds","quantity":1,"unit":"tsp"},{"id":"457368df-1799-47e3-b792-63a826096707","name":"Lime","quantity":1,"unit":"pieces"}]'::jsonb,
       array['Cook the rice according to pack instructions, then spread out to cool slightly while you prepare everything else. Cook the edamame in boiling water for 3–4 minutes, drain and set aside.', 'Make the dressing: mix the soy sauce, sesame oil, rice vinegar and honey in a small bowl.', 'Stir the mayonnaise with the sriracha in another small bowl. Slice the smoked salmon into wide ribbons. Slice the avocado, halve and finely slice the cucumber, finely slice the salad onions, and dice the mango (if using).', 'Divide the rice between two bowls. Arrange the smoked salmon, avocado, cucumber, edamame, mango and pickled ginger on top. Drizzle over the dressing and the spicy mayo, scatter with sesame seeds and serve with lime wedges.']::text[], array['lunch', 'dinner']::text[], 2, 'Mango is optional — it adds a sweet contrast that works well with the smoked salmon. Sriracha and sesame seeds are optional too. Swap the rice for brown rice for extra fibre.', '', array['fish', 'no-cook', 'quick', 'healthy']::text[]
where not exists (
  select 1 from recipes where household_id is null and title = 'Salmon Poke Bowl'
);

